SELECT id, owner_username AS ownerUsername, title, description, type, status, thumb_320_url AS thumb320Url, thumb_720_url AS thumb720Url, thumb_1280_url AS thumb1280Url, tags_text AS tagsText, rating_avg AS ratingAvg, rating_count AS ratingCount, download_count AS downloadCount, apply_count AS applyCount, created_at AS createdAt, published_at AS publishedAt FROM wallpaper_asset WHERE deleted = 0 AND status = 'published'
AND type = #{type}
AND ( title LIKE CONCAT('%', #{keyword}, '%') OR owner_username LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR tags_text LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY rating_avg DESC, rating_count DESC, id DESC ORDER BY apply_count DESC, download_count DESC, id DESC ORDER BY published_at DESC, id DESC
LIMIT #{offset}, #{limit}

SELECT id, owner_username AS ownerUsername, title, description, type, status, original_url AS originalUrl, thumb_320_url AS thumb320Url, thumb_720_url AS thumb720Url, thumb_1280_url AS thumb1280Url, tags_text AS tagsText, rating_avg AS ratingAvg, rating_count AS ratingCount, download_count AS downloadCount, apply_count AS applyCount, created_at AS createdAt, updated_at AS updatedAt, published_at AS publishedAt FROM wallpaper_asset WHERE deleted = 0
AND type = #{type}
AND status = #{status}
AND ( title LIKE CONCAT('%', #{keyword}, '%') OR owner_username LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR tags_text LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY id DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE wallpaper_asset
SET title = #{title},
    description = #{description},
    type = #{type},
    tags_text = #{tagsText},
    status = 'pending',
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND owner_username = #{ownerUsername}
  AND deleted = 0

UPDATE wallpaper_asset
SET deleted = 1,
    status = 'deleted',
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND owner_username = #{ownerUsername}
  AND deleted = 0

